import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const FALLBACK_ARTISTS = [
  
  { username: "Arijit Singh", image: "data:image/jpeg;base64," },
  { username: "Vishal Mishra", image: "data:image/jpeg;base64," },
  { username: "Shreya Ghoshal", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTr66jMxa9HrwsXjQiM78Pfb7j9rq_1bY_1yGPUYb9LAQ&s=10" },
  { username: "Neha Kakkar", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSdBiPq0tT8qF9pIwn6KFkZJm-c7tu2up0joe0pKaGMmA&s=10" },
  { username: "Armaan Malik", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS7d-6A1VLmXrcsWmEGdsox9_7G2zqO-NIUtJHpVG9lYA&s=10" },
  { username: "Jubin Nautiyal", image: "data:image/jpeg;base64," },
  { username: "Atif Aslam", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQLWf3jE1xlMO68HAQ-cg9tHUON0S5UduA_dusqrXPJvA&s=10" },
  { username: "Darshan Raval", image: "data:image/jpeg;base64," },
  { username: "B Praak", image: "data:image/jpeg;base64," },
  { username: "Pritam", image: "data:image/jpeg;base64," }
];

const PopularArtists = () => {
  
  const [artists, setArtists] = useState([]);
  const navigate = useNavigate();
  useEffect(() => {
  const fetchArtists = async () => {
    try {
      const res = await fetch("http://localhost:3000/api/music", {
        credentials: "include",
      });

      const data = await res.json();

      // Extract unique artists
      const uniqueMap = {};

     (data.music || []).forEach((song, index) => {
  if (song.artist?.username) {

    const fallbackArtist = FALLBACK_ARTISTS.find(
      (a) => a.username === song.artist.username
    );

    uniqueMap[song.artist.username] = {
      ...song.artist,
      image:
        song.artist.image ||
        fallbackArtist?.image ||
        `https://picsum.photos/200/200?random=${index + 1}`,
    };
  }
});
      const fetched = Object.values(uniqueMap);

      const fetchedNames = new Set(
        fetched.map((artist) => artist.username)
      );

      // Add fallback artists that are not already present
      const filler = FALLBACK_ARTISTS.filter(
        (artist) => !fetchedNames.has(artist.username)
      );

      const combined = [...fetched, ...filler].slice(0, 10);

      setArtists(combined);
    } catch (err) {
      console.error("Error fetching artists:", err);
      setArtists(FALLBACK_ARTISTS.slice(0, 10));
    }
  };

  fetchArtists();
}, []);

  return (
  <div className="text-white mt-8">

    {/* HEADER */}
    <div className="flex items-center justify-between px-4 sm:px-6 mb-5">
      <h2 className="text-xl sm:text-2xl font-bold">
        Popular Artists 
      </h2>

      <button className="text-sm text-gray-400 hover:text-white">
        Show all
      </button>
    </div>

    {/* HORIZONTAL SCROLL */}
    <div
      className="
        flex
        gap-6
        px-4 sm:px-6
        pb-2
        overflow-x-auto
        no-scrollbar
        scroll-smooth
        snap-x snap-mandatory
      "
    >
      {artists.map((artist, i) => (
 <div
    key={artist.username || i}
    onClick={() =>
        navigate(`/artist/${encodeURIComponent(artist.username)}`, {
  state: {
    artist
  }
})
    }
    className="flex flex-col items-center flex-shrink-0 w-40 cursor-pointer"
>
        
          {/* IMAGE */}
          <div
            className="
              w-36
              h-36
              rounded-full
              overflow-hidden
              border-2
              border-green-500
              transition-transform
              duration-300
              group-hover:scale-105
            "
          >
            <img
  src={
   artist.image ||
artist.profileImage ||
""
    `https://picsum.photos/200/200?random=${encodeURIComponent(
      artist.username
    )}`
  }
  alt={artist.username}
  className="
    w-full
    h-full
    object-cover
    transition-transform
    duration-300
    group-hover:scale-110
  "
 onError={(e) => {
  e.target.src = "/default-artist.png";
}}
/>
          </div>

          {/* NAME */}
          <p className="mt-3 text-sm font-semibold text-center w-full truncate">
            {artist.username}
          </p>

          <p className="text-xs text-gray-400">
            Artist
          </p>
        </div>
      ))}
    </div>
  </div>
);
};

export default PopularArtists;